import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { instructorAPI } from '../../api/client';
import s from './InstructorPage.module.css';

/* ─── helpers ─────────────────────────────────────────────────────────────── */
const DAYS   = ['ПН','ВТ','СР','ЧТ','ПТ','СБ','ВС'];
const MONTHS = ['ЯНВАРЬ','ФЕВРАЛЬ','МАРТ','АПРЕЛЬ','МАЙ','ИЮНЬ',
                'ИЮЛЬ','АВГУСТ','СЕНТЯБРЬ','ОКТЯБРЬ','НОЯБРЬ','ДЕКАБРЬ'];

function getWeekDates(offset = 0) {
  const today  = new Date();
  const dow    = (today.getDay() + 6) % 7;
  const monday = new Date(today);
  monday.setDate(today.getDate() - dow + offset * 7);
  return Array.from({length:7}, (_,i) => {
    const d = new Date(monday); d.setDate(monday.getDate()+i); return d;
  });
}
const toISO  = d => d.toISOString().slice(0,10);
const fmtRU  = d => [String(d.getDate()).padStart(2,'0'),
                     String(d.getMonth()+1).padStart(2,'0'),
                     d.getFullYear()].join('.');
const initials = name => name ? name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase() : '?';

function Sp() { return <div className={s.spinner}/>; }

/* ═══════════════════════════════════════════════════════════════════════════
   NOTIFICATIONS SHEET
════════════════════════════════════════════════════════════════════════════ */
const TYPE_LABEL = {
  booking_new:    'Новая запись',
  booking_cancel: 'Отмена записи',
  reminder_24h:   'Напоминание',
  reminder_2h:    'Напоминание',
  slot_added:     'Изменение расписания',
  instructor_set: 'Прикреплён инструктор',
  invoice_status: 'Статус счёта',
};

function NotificationsSheet({ onClose }) {
  const [items, setItems]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    instructorAPI.getNotifications()
      .then(r => setItems(Array.isArray(r.data) ? r.data : []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const markRead = async id => {
    await instructorAPI.markRead(id).catch(()=>{});
    setItems(p => p.map(n => n.id===id ? {...n, is_read:true} : n));
  };

  return (
    <div className={s.overlay} onClick={e => e.target===e.currentTarget && onClose()}>
      <div className={s.notifSheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Уведомления</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>
        {loading ? <div className={s.loading}><Sp/></div>
        : items.length===0
          ? <div className={s.empty}>Нет уведомлений</div>
          : <div className={s.notifList}>
              {items.map(n => (
                <div key={n.id} className={s.notifCard} onClick={() => !n.is_read && markRead(n.id)}>
                  <div className={s.notifBody}>
                    <div className={s.notifType}>{TYPE_LABEL[n.type] || n.type}</div>
                    <div className={s.notifText}>{n.text}</div>
                  </div>
                  {!n.is_read && <div className={s.notifDot}/>}
                </div>
              ))}
            </div>
        }
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SCHEDULE — Create modal (bottom sheet)
════════════════════════════════════════════════════════════════════════════ */
function CreateSlotSheet({ selectedDate, onClose, onSaved }) {
  const [startH, setStartH] = useState('10');
  const [startM, setStartM] = useState('00');
  const [endH,   setEndH]   = useState('12');
  const [endM,   setEndM]   = useState('00');
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    const start = `${startH.padStart(2,'0')}:${startM.padStart(2,'0')}`;
    const end   = `${endH.padStart(2,'0')}:${endM.padStart(2,'0')}`;
    try {
      await instructorAPI.createSlot({ date: selectedDate, start_time: start, end_time: end });
      onSaved();
    } catch(e) {
      setErr(e.response?.data?.detail || JSON.stringify(e.response?.data) || 'Ошибка');
    } finally { setLoading(false); }
  };

  return (
    <div className={s.overlay} onClick={e => e.target===e.currentTarget && onClose()}>
      <div className={s.sheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Новый слот</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>

        {/* Date (readonly) */}
        <div className={s.fieldGroup}>
          <label className={s.fieldLabel}>Дата</label>
          <div className={s.fieldInputMuted}>{selectedDate.split('-').reverse().join('.')}</div>
        </div>

        {/* Time pickers */}
        <div className={s.fieldGroup}>
          <div className={s.timeHeader}>Время</div>
          <div className={s.timeRow}>
            <div className={s.timeCol}>
              <span className={s.timeColLabel}>Начало</span>
              <input className={s.fieldInput} type="time"
                value={`${startH.padStart(2,'0')}:${startM.padStart(2,'0')}`}
                onChange={e => { const [h,m]=e.target.value.split(':'); setStartH(h); setStartM(m); }} />
            </div>
            <div className={s.timeCol}>
              <span className={s.timeColLabel}>Конец</span>
              <input className={s.fieldInput} type="time"
                value={`${endH.padStart(2,'0')}:${endM.padStart(2,'0')}`}
                onChange={e => { const [h,m]=e.target.value.split(':'); setEndH(h); setEndM(m); }} />
            </div>
          </div>
        </div>

        {err && <p className={s.err}>{err}</p>}
        <button className={`${s.btnBlue}`} onClick={save} disabled={loading}>
          {loading ? <Sp/> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SCHEDULE — Edit modal (bottom sheet)
════════════════════════════════════════════════════════════════════════════ */
function EditSlotSheet({ slot, onClose, onSaved, onDeleted }) {
  const [startVal, setStartVal] = useState(slot.start_time);
  const [endVal,   setEndVal]   = useState(slot.end_time);
  const [loading,  setLoading]  = useState(false);
  const [delLoad,  setDelLoad]  = useState(false);
  const [err,      setErr]      = useState('');
  const booked = slot.status === 'booked';

  const save = async () => {
    setLoading(true); setErr('');
    try {
      await instructorAPI.updateSlot(slot.id, { start_time: startVal, end_time: endVal });
      onSaved();
    } catch(e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  const del = async () => {
    if (!window.confirm('Удалить слот?')) return;
    setDelLoad(true);
    try { await instructorAPI.deleteSlot(slot.id); onDeleted(); }
    catch(e) { setErr(e.response?.data?.detail || 'Ошибка при удалении'); }
    finally { setDelLoad(false); }
  };

  return (
    <div className={s.overlay} onClick={e => e.target===e.currentTarget && onClose()}>
      <div className={s.sheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Редактирование</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>

        {/* Date */}
        <div className={s.fieldGroup}>
          <label className={s.fieldLabel}>Дата</label>
          <div className={s.fieldInputMuted}>{slot.date.split('-').reverse().join('.')}</div>
        </div>

        {/* Time */}
        <div className={s.fieldGroup}>
          <div className={s.timeHeader}>Время</div>
          <div className={s.timeRow}>
            <div className={s.timeCol}>
              <span className={s.timeColLabel}>Начало</span>
              <input className={s.fieldInput} type="time" value={startVal} disabled={booked}
                onChange={e => setStartVal(e.target.value)} />
            </div>
            <div className={s.timeCol}>
              <span className={s.timeColLabel}>Конец</span>
              <input className={s.fieldInput} type="time" value={endVal} disabled={booked}
                onChange={e => setEndVal(e.target.value)} />
            </div>
          </div>
        </div>

        {/* Booked toggle (visual only) */}
        <div className={s.bookedRow}>
          <span className={s.bookedLabel}>Забронировано</span>
          {booked
            ? <div className={s.toggleTrack}><div className={s.toggleThumb}/></div>
            : <div style={{width:38,height:22,background:'#D0D0D0',borderRadius:11,position:'relative'}}>
                <div style={{position:'absolute',left:2,top:2,width:18,height:18,background:'white',borderRadius:'50%'}}/>
              </div>
          }
        </div>

        {err && <p className={s.err}>{err}</p>}

        {!booked ? (
          <>
            <button className={s.btnBlue} onClick={save} disabled={loading}>
              {loading ? <Sp/> : 'Сохранить'}
            </button>
            <button className={`${s.btnOrange} ${s.btnGap}`} onClick={del} disabled={delLoad}>
              {delLoad ? <Sp/> : 'Удалить'}
            </button>
          </>
        ) : (
          <button className={`${s.btnGray} ${s.btnGap}`} onClick={onClose}>Закрыть</button>
        )}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SCHEDULE TAB
════════════════════════════════════════════════════════════════════════════ */
function ScheduleTab() {
  const [weekOffset, setWeekOffset]   = useState(0);
  const [selectedDay, setSelectedDay] = useState(new Date());
  const [slots, setSlots]             = useState([]);
  const [loading, setLoading]         = useState(true);
  const [modal, setModal]             = useState(null); // null | 'create' | slot
  const today = new Date();
  const weekDates = getWeekDates(weekOffset);

  const load = useCallback(() => {
    setLoading(true);
    instructorAPI.getSlots({ week: toISO(weekDates[0]) })
      .then(r => setSlots(Array.isArray(r.data) ? r.data : []))
      .catch(() => setSlots([]))
      .finally(() => setLoading(false));
  // eslint-disable-next-line
  }, [weekOffset]);

  useEffect(() => { load(); }, [load]);

  const f = weekDates[0], l = weekDates[6];
  const monthLabel = f.getMonth()===l.getMonth()
    ? MONTHS[f.getMonth()]
    : `${MONTHS[f.getMonth()]} / ${MONTHS[l.getMonth()]}`;

  const selStr   = toISO(selectedDay);
  const daySlots = slots.filter(s=>s.date===selStr).sort((a,b)=>a.start_time.localeCompare(b.start_time));

  return (
    <>
      <div className={s.schedulePage}>
        <h1 className={s.pageTitle}>Расписание</h1>

        {/* Calendar */}
        <div className={s.calendarCard}>
          <div className={s.calendarHeader}>
            <button className={s.navBtn} onClick={()=>setWeekOffset(p=>p-1)}>←</button>
            <span className={s.monthLabel}>{monthLabel}</span>
            <button className={s.navBtn} onClick={()=>setWeekOffset(p=>p+1)}>→</button>
          </div>
          <div className={s.weekRow}>
            {DAYS.map(d=><span key={d} className={s.dayName}>{d}</span>)}
          </div>
          <div className={s.daysRow}>
            {weekDates.map((d,i)=>{
              const isTd = d.toDateString()===today.toDateString();
              const isSel= d.toDateString()===selectedDay.toDateString();
              return (
                <button key={i}
                  className={[s.dayBtn, isTd?s.dayToday:'', isSel?s.daySelected:''].filter(Boolean).join(' ')}
                  onClick={()=>setSelectedDay(new Date(d))}>
                  {d.getDate()}
                </button>
              );
            })}
          </div>
        </div>

        {/* Day header */}
        <div className={s.dayHeader}>
          <span className={s.dayDate}>{fmtRU(selectedDay)}</span>
          <button className={s.addBtn} onClick={()=>setModal('create')}>+</button>
        </div>

        {/* Slots */}
        {loading
          ? <div className={s.loading}><Sp/></div>
          : daySlots.length===0
            ? <div className={s.empty}>Нет слотов на выбранный день</div>
            : <div className={s.slotList}>
                {daySlots.map(slot=>(
                  <div key={slot.id}
                    className={`${s.slot} ${slot.status==='booked'?s.slotBlue:s.slotWhite}`}
                    onClick={()=>setModal(slot)}>
                    <div className={s.slotTime}>{slot.start_time} - {slot.end_time}</div>
                    <div className={s.slotTitle}>
                      {slot.status==='booked' ? (slot.student_name||'Студент') : 'Свободно'}
                    </div>
                    <div className={s.slotLoc}>📍 Энтузиастов 12, офис 302</div>
                  </div>
                ))}
              </div>
        }
      </div>

      {/* Bottom sheets */}
      {modal==='create' && (
        <CreateSlotSheet selectedDate={selStr} onClose={()=>setModal(null)} onSaved={()=>{setModal(null);load();}}/>
      )}
      {modal && modal!=='create' && (
        <EditSlotSheet slot={modal} onClose={()=>setModal(null)}
          onSaved={()=>{setModal(null);load();}} onDeleted={()=>{setModal(null);load();}}/>
      )}
    </>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   PROFILE — Car sheet
════════════════════════════════════════════════════════════════════════════ */
function CarSheet({ profile, onClose, onSaved }) {
  const [form, setForm]     = useState({
    car_brand:    profile?.car_brand    || '',
    car_color:    profile?.car_color    || '',
    car_plate:    profile?.car_plate    || '',
    car_type_kpp: profile?.car_type_kpp || 'МКПП',
  });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateCar(form); onSaved(); }
    catch(e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  return (
    <div className={s.overlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={s.sheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Автомобиль</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>
        {[
          {key:'car_brand',ph:'Lada Granta', lbl:'Марка автомобиля'},
          {key:'car_color',ph:'Белый',       lbl:'Цвет'},
          {key:'car_plate',ph:'X000XX774',   lbl:'Регистрационный номер'},
        ].map(({key,ph,lbl})=>(
          <div className={s.fieldGroup} key={key}>
            <label className={s.fieldLabel}>{lbl}</label>
            <input className={s.fieldInput} placeholder={ph} value={form[key]}
              onChange={e=>setForm(p=>({...p,[key]:e.target.value}))}/>
          </div>
        ))}
        <div className={s.fieldGroup}>
          <label className={s.fieldLabel}>Тип КПП</label>
          <select className={s.fieldInput} value={form.car_type_kpp}
            onChange={e=>setForm(p=>({...p,car_type_kpp:e.target.value}))}>
            <option value="МКПП">МКПП (механика)</option>
            <option value="АКПП">АКПП (автомат)</option>
          </select>
        </div>
        {err && <p className={s.err}>{err}</p>}
        <button className={s.btnBlue} onClick={save} disabled={loading}>
          {loading ? <Sp/> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   PROFILE — Limit sheet
════════════════════════════════════════════════════════════════════════════ */
function LimitSheet({ profile, onClose, onSaved }) {
  const [lim, setLim]       = useState(profile?.weekly_limit ?? 3);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateLimit({ weekly_limit: lim }); onSaved(); }
    catch(e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  return (
    <div className={s.overlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={s.sheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Лимит занятий</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>
        <p style={{fontSize:13,color:'#8A8A8A',marginBottom:20,lineHeight:1.5}}>
          Максимальное количество занятий в неделю, на которое может записаться студент.
        </p>
        <div className={s.limitRow}>
          <button className={s.limitBtn} onClick={()=>setLim(p=>Math.max(1,p-1))}>−</button>
          <span className={s.limitVal}>{lim}</span>
          <button className={s.limitBtn} onClick={()=>setLim(p=>Math.min(10,p+1))}>+</button>
        </div>
        {err && <p className={s.err}>{err}</p>}
        <button className={`${s.btnBlue} ${s.btnGap}`} onClick={save} disabled={loading}>
          {loading ? <Sp/> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   PROFILE TAB
════════════════════════════════════════════════════════════════════════════ */
function ProfileTab() {
  const { logout }   = useAuth();
  const navigate     = useNavigate();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [sheet, setSheet]     = useState(null); // null | 'car' | 'limit' | 'notif'

  const load = () => {
    instructorAPI.getProfile()
      .then(r => setProfile(r.data))
      .catch(()=>{})
      .finally(()=>setLoading(false));
  };
  useEffect(()=>{ load(); },[]);

  const fullName = profile
    ? [profile.last_name,profile.first_name,profile.patronymic].filter(Boolean).join(' ')
    : '—';
  const carLabel = profile?.car_brand
    ? `${profile.car_color?profile.car_color+' ':''}${profile.car_brand} ${profile.car_plate||''}`.trim()
    : 'Не указан';

  return (
    <>
      <div className={s.profilePage}>
        <div className={s.profileHeader}>
          <h1 className={s.pageTitle} style={{margin:0}}>Профиль</h1>
          <div style={{display:'flex',gap:10}}>
            <button className={s.notifBtn} onClick={()=>setSheet('notif')} title="Уведомления">
              {/* Bell icon */}
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none">
                <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0"
                  stroke="#F5A623" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            </button>
          </div>
        </div>

        {loading ? <div className={s.loading}><Sp/></div> : (
          <>
            <div className={s.avatar}>
              <svg width="52" height="52" viewBox="0 0 52 52" fill="none">
                <circle cx="26" cy="20" r="11" fill="#B0B8C9"/>
                <ellipse cx="26" cy="46" rx="20" ry="11" fill="#B0B8C9"/>
              </svg>
            </div>
            <div className={s.profileName}>{fullName}</div>

            {/* Car card */}
            <div className={s.infoCard} onClick={()=>setSheet('car')}>
              <div className={s.infoCardRow}>
                <span className={s.infoCardTitle}>Автомобиль</span>
              </div>
              <div className={s.infoCardValue}>{carLabel}</div>
            </div>

            {/* Limit card */}
            <div className={s.infoCard} onClick={()=>setSheet('limit')}>
              <div className={s.infoCardRow}>
                <span className={s.infoCardTitle}>Лимит</span>
                <span className={s.editIcon}>✎</span>
              </div>
              <div className={s.infoCardValueMuted}>
                Максимальное количество занятий в неделю, на которое может записаться студент —{' '}
                <strong style={{color:'#1A1A1A'}}>{profile?.weekly_limit??3}</strong>.
              </div>
            </div>

            <button className={s.logoutBtn} onClick={()=>{logout();navigate('/login');}}>
              Выйти
            </button>
          </>
        )}
      </div>

      {sheet==='car'   && <CarSheet   profile={profile} onClose={()=>setSheet(null)} onSaved={()=>{setSheet(null);load();}}/>}
      {sheet==='limit' && <LimitSheet profile={profile} onClose={()=>setSheet(null)} onSaved={()=>{setSheet(null);load();}}/>}
      {sheet==='notif' && <NotificationsSheet onClose={()=>setSheet(null)}/>}
    </>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   REQUESTS TAB (my students)
════════════════════════════════════════════════════════════════════════════ */
function RequestsTab() {
  const [students, setStudents] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(()=>{
    instructorAPI.getStudents()
      .then(r=>setStudents(Array.isArray(r.data)?r.data:[]))
      .catch(()=>setStudents([]))
      .finally(()=>setLoading(false));
  },[]);

  return (
    <div className={s.requestsPage}>
      <h1 className={s.pageTitle}>Студенты</h1>
      {loading ? <div className={s.loading}><Sp/></div>
      : students.length===0 ? <div className={s.empty}>Студенты не назначены</div>
      : students.map(st=>(
        <div key={st.id} className={s.studentCard}>
          <div className={s.studentAvatar}>{initials(st.full_name)}</div>
          <div>
            <div className={s.studentName}>{st.full_name}</div>
            <div className={s.studentMeta}>
              📞 {st.phone_number} · {st.count_lessons} ч. · {st.type_kpp||'—'}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

